COMMENT ON COLUMN "public"."message_ws_metric"."id" IS E'主键ID';
COMMENT ON COLUMN "public"."message_ws_metric"."bucket_at" IS E'统计桶时间（按分钟截断）';
COMMENT ON COLUMN "public"."message_ws_metric"."request_count" IS E'WS 请求总数';
